const input = $input.first().json;
const item = input.message || input.body || input;
const textBody = item.text || item.caption || item.message?.text || '';

function findContact(obj) {
  if (!obj || typeof obj !== 'object') return null;
  const contact = obj.contact || obj.sender_contact || obj.from || obj.sender?.wa_id || '';
  if (typeof contact === 'string') {
    if (contact.includes('t.me/')) return contact.split('t.me/')[1];
    if (contact.startsWith('tg_id_')) return contact;
    if (contact.startsWith('@')) return contact;
    if (/^\d{7,15}$/.test(contact)) return 'tg_id_' + contact;
  }
  return null;
}

let sc = findContact(item) || findContact(input);
if (sc && !sc.startsWith('tg_id_')) {
  sc = sc.trim();
  if (!sc.startsWith('@')) sc = '@' + sc;
}

const sourceChatId = item.chatId || item.chat?.id || input.source_chat_id || '';

return [{ json: {
  ...item,
  platform: 'Telegram',
  sender_contact: sc || 'No_Username',
  final_contact: sc || 'No_Username',
  source_chat_id: sourceChatId,
  texto_limpio: textBody.trim(),
  looksValuable: textBody.length > 5
}}];

const input = $input.first().json;

// n8n webhook wraps the request body in input.body
// RAW Whapi format: input.body = { messages: [{from, text, chat_id, ...}], event, channel_id }
// Gateway format:   input.body = { platform, from, sender, chatId, body:{text}, text, ... }
const body = input.body || input;
const whapiMsg = (body.messages && body.messages[0]) ? body.messages[0] : null;

// Extract text from all possible formats
let textBody = '';
if (whapiMsg && whapiMsg.text && typeof whapiMsg.text.body === 'string') {
  textBody = whapiMsg.text.body;  // RAW Whapi format
}
if (!textBody && typeof body.text === 'string') textBody = body.text;
if (!textBody && body.body && typeof body.body.text === 'string') textBody = body.body.text;
if (!textBody && typeof body.body === 'string') textBody = body.body;
if (!textBody && input.text && typeof input.text === 'string') textBody = input.text;
if (!textBody && input.message && typeof input.message.text === 'string') textBody = input.message.text;

textBody = textBody.replace(/\*/g, '').replace(/_/g, '').trim();

function getPhone(val) {
  if (!val) return null;
  let s = String(typeof val === 'object' ? (val.id || val.author || val.from || val.phone || val.number || val.wa_id || val.remoteJid || '') : val);
  if (s.includes('@g.us') || s.includes('-')) return null;
  const digits = s.replace(/\D/g, '');
  return (digits.length >= 7 && digits.length <= 15) ? digits : null;
}

// Check RAW Whapi format (messages[0].from) FIRST, then gateway format fields
let sc = getPhone(whapiMsg && whapiMsg.from)
      || getPhone(body.from)
      || getPhone(body.sender)
      || getPhone(body.author)
      || getPhone(input.from)
      || getPhone(input.sender)
      || null;

// Final fallback: extract international phone from message text (e.g. 0044XXXX, +44XXXX)
if (!sc && textBody) {
  const intlRx = /(?:(?:\+|00)[1-9][\d]{8,13})/g;
  const found = textBody.match(intlRx) || [];
  for (const p of found) {
    const d = p.replace(/\D/g, '');
    const norm = d.startsWith('00') ? d.substring(2) : d;
    if (norm.length >= 7 && norm.length <= 15 && !norm.startsWith('0')) {
      sc = norm;
      break;
    }
  }
}

const senderFinal = sc || "No disponible";
const chatId = (whapiMsg && whapiMsg.chat_id) || body.chatId || body.chat_id || body.jid || input.chatId || input.chat_id || null;
const chatName = (whapiMsg && whapiMsg.chat_name) || body.chat_name || input.chat_name || '';
const msgType = (whapiMsg && whapiMsg.type) || body.type || input.type || 'text';

if (!textBody || textBody.length < 5 || ['unknown', 'reaction', 'sticker', 'image', 'video', 'audio', 'document', 'location', 'contacts', 'poll'].includes(msgType)) {
  return [];
}

return [{ json: {
  platform: "WhatsApp",
  sender_contact: senderFinal,
  final_contact: senderFinal,
  from: senderFinal,
  source_chat_id: chatId,
  chat_name: chatName,
  texto_limpio: textBody,
  looksValuable: true
}}];

const results = [];
const HARD_BLOCK = new Set(["crypto", "binance", "casino", "usdt", "bitcoin", "wallet", "trading", "инди", "контент", "onlyfans", "вирт", "sugar baby", "sugar daddy", "masaje erotico", "ingles", "english", "videollamada", "video call", "видеозвонок", "chamada de video", "contenido", "conteudo", "gratis", "бесплатно", "grátis", "paja", "wank", "дрочить", "punheta", "follar", "трахать", "foder", "polvo", "трах", "foda", "telefonista", "telefon", "телефонист", "venta de entradas", "vendo entradas", "vendo dos entradas"]);
const BANNED_PREFIXES = ["58", "57", "92", "91", "62", "244"];

function norm(v) { return String(v || "").toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, ""); }

for (const item of $input.all()) {
  const data = item.json;
  const text = norm(data.texto_limpio);
  const sender = String(data.final_contact || data.from || "").replace(/\D/g, "");

  // Prefijo baneado SOLO para Telegram — grupos de WA tienen miembros internacionales (VE/CO legítimos)
  if (data.platform !== 'WhatsApp' && BANNED_PREFIXES.some(p => sender.startsWith(p))) continue;

  // Bloquear por palabra clave prohibida
  if ([...HARD_BLOCK].some(k => text.includes(k))) continue;

  // Si no hay texto, no tiene sentido enviarlo a la IA
  if (!text || text.length < 10) continue;

  // Solo los que pasan todos los filtros salen del nodo
  results.push(item);
}
return results;

const results = [];
const store = $getWorkflowStaticData('global');
if (!store.history) store.history = [];

const now = Date.now();
const TTL = 30 * 60 * 1000;
store.history = store.history.filter(h => now - h.time < TTL);

for (const item of $input.all()) {
  const fp = String(item.json.texto_limpio || '').substring(0, 100);
  const sender = String(item.json.sender_contact || item.json.from || '');

  // Dedup por contenido solamente (sender puede variar si no se extrae bien)
  if (!store.history.some(h => h.fp === fp)) {
    store.history.push({ time: now, fp, sender });
    results.push(item);
  }
}
return results;

// PARSE JSON v5.9 (ALL LANGS + REAL SENDER RECOVERY)
const input = $json;
const rawText = input.output || input.text || "";
const cleanText = rawText.replace(/```json|```/g, '').trim();

let parsed = {};
try {
  if (cleanText) parsed = JSON.parse(cleanText);
} catch (e) {
  const catMatch = cleanText.match(/"category"\s*:\s*"(.*?)"/i);
  const cityMatch = cleanText.match(/"city"\s*:\s*"(.*?)"/i);
  if (catMatch) parsed.category = catMatch[1];
  if (cityMatch) parsed.city = cityMatch[1];
}

// Safely get texto_limpio from Dedup Hash1
let originalText = "";
try {
    originalText = $('Dedup Hash1').item.json.texto_limpio || "";
} catch(e) {
    try {
        originalText = $('Pre-Filter Unified1').item.json.texto_limpio || "";
    } catch(err) {}
}

const lowerRaw = originalText.toLowerCase();
const isJobish = lowerRaw.includes("busco") || lowerRaw.includes("disponible") || lowerRaw.includes("casting") || lowerRaw.includes("tour") || lowerRaw.length > 20;

// RECOVER SENDER CONTACT FROM EARLIER NODES!
let origContact = "Desconocido";
try { origContact = $('Extract Metadata WA1').item.json.sender_contact || "Desconocido"; } catch(e) {}
if (origContact === "Desconocido" || origContact === "No disponible") {
    try { origContact = $('Extract Metadata TG1').item.json.sender_contact || origContact; } catch(e) {}
}
if (origContact === "Desconocido" || origContact === "No disponible") {
    try { origContact = $('Dedup Hash1').item.json.sender_contact || origContact; } catch(e) {}
}
if (origContact === "Desconocido") {
    origContact = input.sender_contact || input.final_contact || "Desconocido";
}

let formattedContact = origContact;
if (formattedContact !== "Desconocido" && formattedContact !== "No disponible") {
    if (!String(formattedContact).startsWith('@') && !String(formattedContact).startsWith('tg_id_')) {
        const s = String(formattedContact).replace(/\D/g, '');
        if (s.length >= 7) {
            formattedContact = "+" + s;
        }
    }
}

let sourceChatId = null;
try { sourceChatId = $('Extract Metadata WA1').item.json.source_chat_id; } catch(e) {}
if (!sourceChatId || sourceChatId === '0') {
  try { sourceChatId = $('Extract Metadata TG1').item.json.source_chat_id; } catch(e) {}
}

const finalData = {
  platform: "WhatsApp", // Default, might be overridden
  contact: formattedContact,
  source_chat_id: sourceChatId || null,
  city: parsed.city || "Global",
  budget: parsed.budget || "Negociable",
  category: (parsed.category || (isJobish ? "evento" : "trash")).toLowerCase(),
  text_es: parsed.text_es || originalText || "Sin descripción",
  title_es: parsed.title_es || (originalText ? originalText.substring(0, 40) : "Nuevo Lead"),

  // RESTORE ALL LANGUAGES
  text_en: parsed.text_en || "",
  title_en: parsed.title_en || "",
  text_ru: parsed.text_ru || "",
  title_ru: parsed.title_ru || "",
